class Solution:
    def numRookCaptures(self, board):
        for i in range(8):
            for j in range(8):
                if board[i][j] == 'R':
                    ri, rj = i, j
        count = 0
        for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            x, y = ri + di, rj + dj
            while 0 <= x < 8 and 0 <= y < 8:
                if board[x][y] == 'p':
                    count += 1
                    break
                if board[x][y] == 'B':
                    break
                x += di
                y += dj
        return count

