class Solution:
    def numRookCaptures(self, board):
        ri = rj = -1
        for i in range(8):
            for j in range(8):
                if board[i][j] == 'R':
                    ri, rj = i, j
                    break
            if ri != -1:
                break
        res = 0
        for di, dj in ((-1, 0), (1, 0), (0, -1), (0, 1)):
            x, y = ri + di, rj + dj
            while 0 <= x < 8 and 0 <= y < 8:
                cell = board[x][y]
                if cell == 'B':
                    break
                if cell == 'p':
                    res += 1
                    break
                x += di
                y += dj
        return res

