var numRookCaptures = function(board) {
    let ri = -1, rj = -1;
    for (let i = 0; i < 8 && ri === -1; i++) {
        for (let j = 0; j < 8; j++) {
            if (board[i][j] === 'R') { ri = i; rj = j; break; }
        }
    }
    let res = 0;
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
    for (const [di, dj] of dirs) {
        let x = ri + di, y = rj + dj;
        while (x >= 0 && x < 8 && y >= 0 && y < 8) {
            const cell = board[x][y];
            if (cell === 'B') break;
            if (cell === 'p') { res++; break; }
            x += di; y += dj;
        }
    }
    return res;
};
